31	/*!
32	  \file
33	  \brief An universal device layer for cutlass 3.x-style kernels.
34	*/
35	
36	#pragma once
37	
38	// common
39	#include "cutlass/cutlass.h"
40	#include "cutlass/device_kernel.h"
41	
42	#if !defined(__CUDACC_RTC__)
43	#include "cutlass/cluster_launch.hpp"
44	#include "cutlass/trace.h"
45	#endif // !defined(__CUDACC_RTC__)
46	
47	////////////////////////////////////////////////////////////////////////////////
48	
49	namespace cutlass::fmha::device {
50	
51	////////////////////////////////////////////////////////////////////////////////
52	////////////////////////////// CUTLASS 3.x API /////////////////////////////////
53	////////////////////////////////////////////////////////////////////////////////
54	
55	template <class Kernel_>
56	class FMHA {
57	public:
58	  using Kernel = Kernel_;
59	
60	  static int const kThreadCount = Kernel::MaxThreadsPerBlock;
61	
62	  /// Argument structure: User API
63	  using Arguments = typename Kernel::Arguments;
64	  /// Argument structure: Kernel API
65	  using Params = typename Kernel::Params;
66	
67	private:
68	
69	  /// Kernel API parameters object
70	  Params params_;
71	
72	  bool is_initialized(bool set = false) {
73	    static bool initialized = false;
74	    if (set) initialized = true;
75	    return initialized;
76	  }
77	
78	public:
79	
80	  /// Access the Params structure
81	  Params const& params() const {
82	    return params_;
83	  }
84	
85	  /// Determines whether the GEMM can execute the given problem.
86	  static Status
87	  can_implement(Arguments const& args) {
88	    if (Kernel::can_implement(args)) {
89	      return Status::kSuccess;
90	    }
91	    else {
92	      return Status::kInvalid;
93	    }
94	  }
95	
96	  /// Gets the workspace size
97	  static size_t
98	  get_workspace_size(Arguments const& args) {
99	    size_t workspace_bytes = 0;
100	    workspace_bytes += Kernel::get_workspace_size(args);
101	    return workspace_bytes;
102	  }
103	
104	  /// Computes the grid shape
105	  static dim3
106	  get_grid_shape(Params const& params) {
107	    return Kernel::get_grid_shape(params);
108	  }
109	
110	  /// Computes the maximum number of active blocks per multiprocessor
111	  static int maximum_active_blocks(int /* smem_capacity */ = -1) {
112	    CUTLASS_TRACE_HOST("FMHA::maximum_active_blocks()");
113	    int max_active_blocks = -1;
114	    int smem_size = Kernel::SharedStorageSize;
115	
116	    // first, account for dynamic smem capacity if needed
117	    cudaError_t result;
118	    if (smem_size >= (48 << 10)) {
119	      CUTLASS_TRACE_HOST("  Setting smem size to " << smem_size);
120	      result = cudaFuncSetAttribute(
121	          device_kernel<Kernel>,
122	          cudaFuncAttributeMaxDynamicSharedMemorySize,
123	          smem_size);
124	      if (cudaSuccess != result) {
125	        result = cudaGetLastError(); // to clear the error bit
126	        CUTLASS_TRACE_HOST(
127	          "  cudaFuncSetAttribute() returned error: "
128	          << cudaGetErrorString(result));
129	        return -1;
130	      }
131	    }
132	
133	    // query occupancy after setting smem size
134	    result = cudaOccupancyMaxActiveBlocksPerMultiprocessor(
135	        &max_active_blocks,
136	        device_kernel<Kernel>,
137	        Kernel::MaxThreadsPerBlock,
138	        smem_size);
139	
140	    if (cudaSuccess != result) {
141	      result = cudaGetLastError(); // to clear the error bit
142	      CUTLASS_TRACE_HOST(
143	        "  cudaOccupancyMaxActiveBlocksPerMultiprocessor() returned error: "
144	        << cudaGetErrorString(result));
145	      return -1;
146	    }
147	
148	    CUTLASS_TRACE_HOST("  max_active_blocks: " << max_active_blocks);
149	    return max_active_blocks;
150	  }
151	
152	  /// Initializes GEMM state from arguments.
153	  Status
154	  initialize(Arguments const& args, void* workspace = nullptr, cudaStream_t stream = nullptr) {
155	    CUTLASS_TRACE_HOST("FMHA::initialize() - workspace "
156	      << workspace << ", stream: " << (stream ? "non-null" : "null"));
157	
158	    // Initialize the workspace
159	    Status status = Kernel::initialize_workspace(args, workspace, stream);
160	    if (status != Status::kSuccess) {
161	      return status;
162	    }
163	
164	    // Initialize the Params structure
165	    params_ = Kernel::to_underlying_arguments(args, workspace);
166	
167	    if (is_initialized()) return Status::kSuccess;
168	
169	    // account for dynamic smem capacity if needed
170	    int smem_size = Kernel::SharedStorageSize;
171	    if (smem_size >= (48 << 10)) {
172	      CUTLASS_TRACE_HOST("  Setting smem size to " << smem_size);
173	      cudaError_t result = cudaFuncSetAttribute(
174	          device_kernel<Kernel>,
175	          cudaFuncAttributeMaxDynamicSharedMemorySize,
176	          smem_size);
177	      if (cudaSuccess != result) {
178	        result = cudaGetLastError(); // to clear the error bit
179	        CUTLASS_TRACE_HOST("  cudaFuncSetAttribute() returned error: " << cudaGetErrorString(result));
180	        return Status::kErrorInternal;
181	      }
182	    }
183	
184	    is_initialized(true);
185	
186	    return Status::kSuccess;
187	  }
188	
189	  /// Update API is preserved in 3.0, but does not guarantee a lightweight update of params.
190	  Status
191	  update(Arguments const& args, void* workspace = nullptr) {
192	    CUTLASS_TRACE_HOST("FMHA()::update() - workspace: " << workspace);
193	
194	    size_t workspace_bytes = get_workspace_size(args);
