237	    int B = size<3, 1>(problem_shape);
238	    int H = size<3, 0>(problem_shape);
239	    int H_K = size<3, 0, 1>(problem_shape);
240	    int H_Q = size<3, 0, 0>(problem_shape);
241	
242	    int q_stride0 = q.stride(0), q_stride1 = q.stride(1), q_stride2 = q.stride(2);
243	    int k_stride0 = k.stride(0), k_stride1 = k.stride(1), k_stride2 = k.stride(2);
244	    int v_stride0 = v.stride(0), v_stride1 = v.stride(1), v_stride2 = v.stride(2);
245	    int o_stride0 = o.stride(0), o_stride1 = o.stride(1), o_stride2 = o.stride(2);
