176	      typename CollectiveEpilogue::TensorStorage epilogue;
177	    };
178	
179	    static constexpr bool IsPersistent = std::is_same_v<TileScheduler, PersistentTileScheduler> || std::is_same_v<TileScheduler, CausalPersistentTileScheduler>;
180	    using MainloopEpilogueStorage = std::conditional_t<IsPersistent, 
181	                                                       std::conditional_t<IsMla, 
182	                                                                          std::conditional_t<CollectiveMainloop::IsOrderLoadEpilogue, UnionType, StructType>,
183	                                                                          StructType>,
184	                                                       UnionType>;
185	
186	    MainloopEpilogueStorage mainloop_epilogue; 
187	
188	    struct PipelineStorage {
189	      alignas(16) typename CollectiveMainloop::PipelineQ::SharedStorage load_q;
190	      alignas(16) typename CollectiveMainloop::PipelineKV::SharedStorage load_kv;
191	      alignas(16) typename CollectiveMainloop::PipelineS::SharedStorage mma_s0;
192	      alignas(16) typename CollectiveMainloop::PipelineS::SharedStorage mma_s1;
193	      alignas(16) typename CollectiveMainloop::PipelineC::SharedStorage s0_corr;
194	      alignas(16) typename CollectiveMainloop::PipelineC::SharedStorage s1_corr;
195	      alignas(16) typename CollectiveMainloop::PipelineO::SharedStorage mma_corr;
196	      alignas(16) typename CollectiveMainloop::PipelineE::SharedStorage corr_epi;
197	      alignas(16) typename CollectiveMainloop::OrderBarrierSoftmax::SharedStorage order_s01;
198	    } pipelines;
199	
200	    uint32_t tmem_base_ptr;
201	  };
202	
203	  static constexpr int SharedStorageSize = sizeof(SharedStorage);
204	
205	  struct Arguments {
206	    ProblemShape problem_shape;
207	    typename CollectiveMainloop::Arguments mainloop;
208	    typename CollectiveEpilogue::Arguments epilogue;
209	    cutlass::KernelHardwareInfo hw_info;
210	  };
211	
212	  struct Params {
213	    ProblemShape problem_shape;
214	    typename CollectiveMainloop::Params mainloop;
215	    typename CollectiveEpilogue::Params epilogue;
216	    typename TileScheduler::Params tile_scheduler;
217	  };
218	
219	  static const int MinBlocksPerMultiprocessor = 1;
220	  static const int MaxThreadsPerBlock = NumWarps * cutlass::NumThreadsPerWarp;
221	  using ArchTag = cutlass::arch::Sm100;
222	
223	  static size_t get_workspace_size(Arguments const& args) { return 0; }
224	  static cutlass::Status initialize_workspace(Arguments const&, void*, cudaStream_t) {
225	    return cutlass::Status::kSuccess;
226	  }
227	
228	  static bool can_implement(Arguments const& args) {
229	    return CollectiveMainloop::can_implement(args.problem_shape, args.mainloop);
230	  }
231	
232	  static dim3 get_grid_shape(Params const& params) {
233	    return TileScheduler::get_grid_shape(params.tile_scheduler);
234	  }
235	
236	  static dim3 get_block_shape() {
237	    dim3 block(MaxThreadsPerBlock, 1, 1);
238	    return block;
239	  }
240	
241	  static Params to_underlying_arguments(Arguments const& args, void* workspace) {
242	    return Params{
243	        args.problem_shape,
244	        CollectiveMainloop::to_underlying_arguments(args.problem_shape, args.mainloop, workspace),
245	        CollectiveEpilogue::to_underlying_arguments(args.problem_shape, args.epilogue, workspace),
246	        TileScheduler::to_underlying_arguments(args.problem_shape, args.hw_info, ClusterShape{}, TileShape{})
247	    };
248	  }
249	
250	  CUTLASS_DEVICE auto apply_batch(const Params &params, ProblemShape const& problem_shape, int batch_idx) {
251	    return apply_variable_length(params.problem_shape, batch_idx);
252	  }
253	
254	  CUTLASS_DEVICE void operator()(const Params &params, char* smem) {
255	#if defined(KERUTILS_ENABLE_SM100A)
256	
257	    TileScheduler tile_scheduler{params.tile_scheduler};
258	
259	    int warp_idx = cutlass::canonical_warp_idx_sync();
260	    auto role = warp_idx_to_WarpRole(warp_idx);
261	    uint32_t lane_predicate = cute::elect_one_sync();
262	
263	    if (role == WarpRole::Load && lane_predicate) {
264	      CollectiveMainloop::prefetch_tma_descriptors(params.mainloop);
265	    }
266	
267	    if (role == WarpRole::Epilogue && lane_predicate) {
268	      CollectiveEpilogue::prefetch_tma_descriptors(params.epilogue);
269	    }
270	
271	    SharedStorage& shared_storage = *reinterpret_cast<SharedStorage*>(smem);
272	
273	    auto get_epilogue_storage = [&]() {
274	      if constexpr (IsMla && CollectiveMainloop::IsOrderLoadEpilogue) {
275	        return reinterpret_cast<typename CollectiveEpilogue::TensorStorage *>(shared_storage.mainloop_epilogue.mainloop.smem_o.data());
276	      } else {
277	        return &shared_storage.mainloop_epilogue.epilogue;
278	      }
279	    };
280	    typename CollectiveEpilogue::TensorStorage & epilogue_storage = *get_epilogue_storage();
281	
282	
283	    typename CollectiveMainloop::PipelineQ::Params pipeline_load_q_params;
284	    if (role == WarpRole::Load) {
285	      pipeline_load_q_params.role = CollectiveMainloop::PipelineQ::ThreadCategory::Producer;
286	    }
287	    if (role == WarpRole::MMA) {
288	      pipeline_load_q_params.role = CollectiveMainloop::PipelineQ::ThreadCategory::Consumer;
289	    }
290	    pipeline_load_q_params.is_leader = lane_predicate && (role == WarpRole::Load);
291	    pipeline_load_q_params.transaction_bytes = CollectiveMainloop::TransactionBytesLoadQ;
292	    typename CollectiveMainloop::PipelineQ pipeline_load_q(
293	      shared_storage.pipelines.load_q,
294	      pipeline_load_q_params,
295	      ClusterShape{},  cute::true_type{}, /*mask calc*/cute::false_type{});
296	    
297	    typename CollectiveMainloop::PipelineKV::Params pipeline_load_kv_params;
298	    if (role == WarpRole::Load) {
299	      pipeline_load_kv_params.role = CollectiveMainloop::PipelineKV::ThreadCategory::Producer;
300	    }
301	    if (role == WarpRole::MMA) {
302	      pipeline_load_kv_params.role = CollectiveMainloop::PipelineKV::ThreadCategory::Consumer;
303	    }
304	    pipeline_load_kv_params.is_leader = lane_predicate && (role == WarpRole::Load);
305	    pipeline_load_kv_params.transaction_bytes = CollectiveMainloop::TransactionBytesLoadK;
306	    typename CollectiveMainloop::PipelineKV pipeline_load_kv(
307	      shared_storage.pipelines.load_kv,
308	      pipeline_load_kv_params,
309	      ClusterShape{}, /*barrier init*/ cute::true_type{}, /*mask calc*/cute::false_type{});
310	
311	    typename CollectiveMainloop::PipelineS::Params pipeline_mma_s0_params;
312	    if (role == WarpRole::MMA) {
313	      pipeline_mma_s0_params.role = CollectiveMainloop::PipelineS::ThreadCategory::Producer;
314	    }
315	    if (role == WarpRole::Softmax0) {
316	      pipeline_mma_s0_params.role = CollectiveMainloop::PipelineS::ThreadCategory::Consumer;
317	    }
318	    pipeline_mma_s0_params.consumer_arv_count = NumWarpsSoftmax * cutlass::NumThreadsPerWarp;
319	    typename CollectiveMainloop::PipelineS pipeline_mma_s0(
320	      shared_storage.pipelines.mma_s0,
321	      pipeline_mma_s0_params,
322	      ClusterShape{}, /*barrier init*/ cute::true_type{}, /*mask calc*/cute::false_type{});
323	
324	    typename CollectiveMainloop::PipelineS::Params pipeline_mma_s1_params;
325	    if (role == WarpRole::MMA) {
326	      pipeline_mma_s1_params.role = CollectiveMainloop::PipelineS::ThreadCategory::Producer;
327	    }
328	    if (role == WarpRole::Softmax1) {
329	      pipeline_mma_s1_params.role = CollectiveMainloop::PipelineS::ThreadCategory::Consumer;
330	    }
331	    pipeline_mma_s1_params.consumer_arv_count = NumWarpsSoftmax * cutlass::NumThreadsPerWarp;
332	    typename CollectiveMainloop::PipelineS pipeline_mma_s1(
333	      shared_storage.pipelines.mma_s1,
334	      pipeline_mma_s1_params,
335	      ClusterShape{}, /*barrier init*/ cute::true_type{}, /*mask calc*/cute::false_type{});
336	
337	    typename CollectiveMainloop::PipelineC::Params pipeline_s0_corr_params;
338	    if (role == WarpRole::Softmax0) {
339	      pipeline_s0_corr_params.role = CollectiveMainloop::PipelineC::ThreadCategory::Producer;
340	    }
341	    if (role == WarpRole::Correction) {
342	      pipeline_s0_corr_params.role = CollectiveMainloop::PipelineC::ThreadCategory::Consumer;
343	    }
344	    pipeline_s0_corr_params.producer_arv_count = NumWarpsSoftmax * cutlass::NumThreadsPerWarp;
345	    pipeline_s0_corr_params.consumer_arv_count = NumWarpsCorrection * cutlass::NumThreadsPerWarp;
346	    typename CollectiveMainloop::PipelineC pipeline_s0_corr(
347	      shared_storage.pipelines.s0_corr,
348	      pipeline_s0_corr_params,
349	      /*barrier init*/ cute::true_type{});
350	
351	    typename CollectiveMainloop::PipelineC::Params pipeline_s1_corr_params;
352	    if (role == WarpRole::Softmax1) {
353	      pipeline_s1_corr_params.role = CollectiveMainloop::PipelineC::ThreadCategory::Producer;
354	    }
355	    if (role == WarpRole::Correction) {
356	      pipeline_s1_corr_params.role = CollectiveMainloop::PipelineC::ThreadCategory::Consumer;
357	    }
358	    pipeline_s1_corr_params.producer_arv_count = NumWarpsSoftmax * cutlass::NumThreadsPerWarp;
359	    pipeline_s1_corr_params.consumer_arv_count = NumWarpsCorrection * cutlass::NumThreadsPerWarp;
360	    typename CollectiveMainloop::PipelineC pipeline_s1_corr(
361	      shared_storage.pipelines.s1_corr,
362	      pipeline_s1_corr_params,
363	      /*barrier init*/ cute::true_type{});
364	
365	    typename CollectiveMainloop::PipelineO::Params pipeline_mma_corr_params;
366	    if (role == WarpRole::MMA) {
367	      pipeline_mma_corr_params.role = CollectiveMainloop::PipelineO::ThreadCategory::Producer;
368	    }
369	    if (role == WarpRole::Correction) {
370	      pipeline_mma_corr_params.role = CollectiveMainloop::PipelineO::ThreadCategory::Consumer;
371	    }
372	    pipeline_mma_corr_params.consumer_arv_count = NumWarpsCorrection * cutlass::NumThreadsPerWarp;
373	    typename CollectiveMainloop::PipelineO pipeline_mma_corr(
374	      shared_storage.pipelines.mma_corr,
375	      pipeline_mma_corr_params,
376	      ClusterShape{}, /*barrier init*/ cute::true_type{}, /*mask calc*/cute::false_type{});
377	
378	    typename CollectiveMainloop::PipelineE::Params pipeline_corr_epi_params;
379	    if (role == WarpRole::Correction) {
380	      pipeline_corr_epi_params.role = CollectiveMainloop::PipelineE::ThreadCategory::Producer;
381	    }
382	    if (role == WarpRole::Epilogue) {
383	      pipeline_corr_epi_params.role = CollectiveMainloop::PipelineE::ThreadCategory::Consumer;
384	    }
385	    pipeline_corr_epi_params.producer_arv_count = NumWarpsCorrection * cutlass::NumThreadsPerWarp;
386	    pipeline_corr_epi_params.consumer_arv_count = NumWarpsEpilogue * cutlass::NumThreadsPerWarp;
387	    typename CollectiveMainloop::PipelineE pipeline_corr_epi(
388	      shared_storage.pipelines.corr_epi,
389	      pipeline_corr_epi_params,
390	      /*barrier init*/ cute::true_type{});
391	
392	    typename CollectiveMainloop::OrderBarrierSoftmax::Params params_order_s01;
393	    params_order_s01.group_id = role == WarpRole::Softmax1 ? 1 : 0;
394	    params_order_s01.group_size = NumWarpsSoftmax * cutlass::NumThreadsPerWarp;
395	    typename CollectiveMainloop::OrderBarrierSoftmax order_s01(
396	      shared_storage.pipelines.order_s01, params_order_s01);
397	
398	    TmemAllocator tmem_allocator;
399	
400	    __syncthreads();
401	
402	    pipeline_load_q.init_masks(ClusterShape{});
403	    pipeline_load_kv.init_masks(ClusterShape{});
404	    pipeline_mma_s0.init_masks(ClusterShape{});
405	    pipeline_mma_s1.init_masks(ClusterShape{});
406	    pipeline_mma_corr.init_masks(ClusterShape{});
407	
408	    typename CollectiveMainloop::PipelineQ::PipelineState pipeline_load_q_consumer_state;
409	    typename CollectiveMainloop::PipelineQ::PipelineState pipeline_load_q_producer_state = cutlass::make_producer_start_state<typename CollectiveMainloop::PipelineQ>();
410	
411	    typename CollectiveMainloop::PipelineKV::PipelineState pipeline_load_kv_consumer_state;
412	    typename CollectiveMainloop::PipelineKV::PipelineState pipeline_load_kv_producer_state = cutlass::make_producer_start_state<typename CollectiveMainloop::PipelineKV>();
413	
414	    typename CollectiveMainloop::PipelineS::PipelineState pipeline_mma_s0_consumer_state;
415	    typename CollectiveMainloop::PipelineS::PipelineState pipeline_mma_s0_producer_state = cutlass::make_producer_start_state<typename CollectiveMainloop::PipelineS>();
416	
417	    typename CollectiveMainloop::PipelineS::PipelineState pipeline_mma_s1_consumer_state;
418	    typename CollectiveMainloop::PipelineS::PipelineState pipeline_mma_s1_producer_state = cutlass::make_producer_start_state<typename CollectiveMainloop::PipelineS>();
419	
420	    typename CollectiveMainloop::PipelineC::PipelineState pipeline_s0_corr_consumer_state;
421	    typename CollectiveMainloop::PipelineC::PipelineState pipeline_s0_corr_producer_state = cutlass::make_producer_start_state<typename CollectiveMainloop::PipelineC>();
422	
423	    typename CollectiveMainloop::PipelineC::PipelineState pipeline_s1_corr_consumer_state;
424	    typename CollectiveMainloop::PipelineC::PipelineState pipeline_s1_corr_producer_state = cutlass::make_producer_start_state<typename CollectiveMainloop::PipelineC>();
425	
426	    typename CollectiveMainloop::PipelineE::PipelineState pipeline_corr_epi_consumer_state;
427	    typename CollectiveMainloop::PipelineE::PipelineState pipeline_corr_epi_producer_state = cutlass::make_producer_start_state<typename CollectiveMainloop::PipelineE>();
428	
429	    typename CollectiveMainloop::PipelineO::PipelineState pipeline_mma_corr_consumer_state;
430	    typename CollectiveMainloop::PipelineO::PipelineState pipeline_mma_corr_producer_state = cutlass::make_producer_start_state<typename CollectiveMainloop::PipelineO>();
431	
432	    CollectiveMainloop mainloop;
433	    CollectiveEpilogue epilogue{params.epilogue};
434	
435	    if (role == WarpRole::Softmax0 || role == WarpRole::Softmax1) {
436	      warpgroup_reg_set<NumRegsSoftmax>();
437	
438	      CUTLASS_PRAGMA_NO_UNROLL
439	      for (; tile_scheduler.is_valid(); ++tile_scheduler) {
440	        auto blk_coord = tile_scheduler.get_block_coord();
441	
442	        auto logical_problem_shape = apply_batch(params,
443	            params.problem_shape, get<2,1>(blk_coord));
444	
445	        if (get<0>(blk_coord) * get<0>(TileShape{}) >= get<0>(logical_problem_shape)) {
446	          continue;
447	        }
448	
449	        if (get<1>(logical_problem_shape) == 0) {
450	          continue;
451	        }
452	
453	        bool is_softmax_0 = role == WarpRole::Softmax0;
454	
455	        mainloop.softmax(
456	           is_softmax_0 ? 0 : 1, blk_coord,
457	           params.mainloop, logical_problem_shape,
458	           is_softmax_0 ? pipeline_mma_s0 : pipeline_mma_s1,
459	           is_softmax_0 ? pipeline_mma_s0_consumer_state : pipeline_mma_s1_consumer_state,
460	           is_softmax_0 ? pipeline_s0_corr : pipeline_s1_corr,
461	           is_softmax_0 ? pipeline_s0_corr_producer_state : pipeline_s1_corr_producer_state,
462	           order_s01
463	         );
464	
465	       }
466	    }
467	    else if (role == WarpRole::Correction) {
468	      cutlass::arch::warpgroup_reg_dealloc<NumRegsCorrection>();
469	
470	      bool has_valid = false;
471	
472	      CUTLASS_PRAGMA_NO_UNROLL
473	      for (; tile_scheduler.is_valid(); ++tile_scheduler) {
474	        auto blk_coord = tile_scheduler.get_block_coord();
475	
476	        auto logical_problem_shape = apply_batch(params,
477	            params.problem_shape, get<2,1>(blk_coord));
478	
479	        if (get<0>(blk_coord) * get<0>(TileShape{}) >= get<0>(logical_problem_shape)) {
480	          continue;
481	        }
482	
483	        has_valid = true;
484	
485	        if (get<1>(logical_problem_shape) == 0) {
486	          mainloop.correction_empty(
487	            blk_coord,
488	            params.mainloop, logical_problem_shape,
489	            params.problem_shape,
490	            epilogue_storage,
491	            pipeline_corr_epi, pipeline_corr_epi_producer_state,
492	            epilogue
493	          );
494	          continue;
495	        }
496	
497	        mainloop.correction(
498	          blk_coord,
499	          params.mainloop, logical_problem_shape,
500	          params.problem_shape,
501	          epilogue_storage,
502	          pipeline_s0_corr, pipeline_s0_corr_consumer_state,
503	          pipeline_s1_corr, pipeline_s1_corr_consumer_state,
504	          pipeline_mma_corr, pipeline_mma_corr_consumer_state,
505	          pipeline_corr_epi, pipeline_corr_epi_producer_state,
506	          epilogue
507	        );
508	
509	      }
510	
511	      if constexpr (NumWarpsEpilogue == 0) {
512	        static_assert(NumWarpsCorrection == 1);
513	
514	        if (has_valid) {
515	          uint32_t free_stage_ptr = shared_storage.tmem_base_ptr;
516	          tmem_allocator.free(free_stage_ptr, TmemAllocator::Sm100TmemCapacityColumns);
517	        }
518	      }
519	
520	    }
521	    else if (role == WarpRole::MMA) {
522	      warpgroup_reg_set<NumRegsOther>();
523	
524	      bool allocated = false;
525	
526	      CUTLASS_PRAGMA_NO_UNROLL
527	      for (; tile_scheduler.is_valid(); ++tile_scheduler) {
528	        auto blk_coord = tile_scheduler.get_block_coord();
529	
530	        auto logical_problem_shape = apply_batch(params,
531	            params.problem_shape, get<2,1>(blk_coord));
532	
533	        if (get<0>(blk_coord) * get<0>(TileShape{}) >= get<0>(logical_problem_shape)) {
534	          continue;
535	        }
536	
537	        if (!allocated) {
538	          tmem_allocator.allocate(TmemAllocator::Sm100TmemCapacityColumns, &shared_storage.tmem_base_ptr);
539	          __syncwarp();
540	          allocated = true;
541	        }
542	
543	        if (get<1>(logical_problem_shape) == 0) {
544	          continue;
545	        }
546	
547	        mainloop.mma(
548	          blk_coord,
549	          params.mainloop, logical_problem_shape,
550	          shared_storage.mainloop_epilogue.mainloop,
551	          pipeline_load_q, pipeline_load_q_consumer_state,
552	          pipeline_load_kv, pipeline_load_kv_consumer_state,
553	          pipeline_mma_s0, pipeline_mma_s0_producer_state,
554	          pipeline_mma_s1, pipeline_mma_s1_producer_state,
555	          pipeline_mma_corr, pipeline_mma_corr_producer_state
556	        );
557	
558	      }
559	    }
560	    else if (role == WarpRole::Load) {
561	      warpgroup_reg_set<NumRegsOther>();
562	
563	      if constexpr (IsMla && CollectiveMainloop::IsOrderLoadEpilogue) {
564	        cutlass::arch::NamedBarrier::arrive((NumWarpsLoad + NumWarpsEpilogue) * NumThreadsPerWarp, 
565	                                      cutlass::arch::ReservedNamedBarriers::EpilogueBarrier);
566	      }
567	
568	      CUTLASS_PRAGMA_NO_UNROLL
569	      for (; tile_scheduler.is_valid(); ++tile_scheduler) {
570	        auto blk_coord = tile_scheduler.get_block_coord();
571	
572	        auto logical_problem_shape = apply_batch(params,
573	            params.problem_shape, get<2,1>(blk_coord));
574	
575	        if (get<0>(blk_coord) * get<0>(TileShape{}) >= get<0>(logical_problem_shape)) {
576	          continue;
577	        }
578	
579	        if (get<1>(logical_problem_shape) == 0) {
580	          continue;
581	        }
582	
583	        mainloop.load(
584	          blk_coord, logical_problem_shape,
585	          params.mainloop, params.problem_shape,
586	          shared_storage.mainloop_epilogue.mainloop,
587	          pipeline_load_q, pipeline_load_q_producer_state,
588	          pipeline_load_kv, pipeline_load_kv_producer_state
589	        );
590	
591	      }
592	    }
593	    else if (role == WarpRole::Epilogue) {
594	      warpgroup_reg_set<NumRegsOther>();
595	
596	      bool has_valid = false;
597	
598	      CUTLASS_PRAGMA_NO_UNROLL
599	      for (; tile_scheduler.is_valid(); ++tile_scheduler) {
600	        auto blk_coord = tile_scheduler.get_block_coord();
601	
602	        auto logical_problem_shape = apply_batch(params,
603	            params.problem_shape, get<2,1>(blk_coord));
604	
605	        if (get<0>(blk_coord) * get<0>(TileShape{}) >= get<0>(logical_problem_shape)) {
606	          continue;
607	        }
608	
609	        has_valid = true;
610	
611	        epilogue.store(
612	          blk_coord, logical_problem_shape,
613	          params.epilogue, params.problem_shape,
614	          epilogue_storage,
615	          pipeline_corr_epi, pipeline_corr_epi_consumer_state
616	        );
617	
618	      }
619	
620	      static_assert(NumWarpsEpilogue <= 1);
621	      if constexpr (NumWarpsEpilogue == 1) {
622	        if(has_valid) {
623	          uint32_t free_stage_ptr = shared_storage.tmem_base_ptr;
624	          tmem_allocator.free(free_stage_ptr, TmemAllocator::Sm100TmemCapacityColumns);
625	        }
626	      }
627	
628	    }
629	    else if (role == WarpRole::Empty) {
630	      warpgroup_reg_set<NumRegsEmpty>();
631	
632	      /* no-op, donate regs and exit */
633	    }
634	#else
635	    if (cute::thread0()) {
636	        CUTE_INVALID_CONTROL_PATH("This kernel only supports sm100\n");
637	    }
638	#endif
639	  }
640	
641	};
642	
643	}  // namespace cutlass::fmha::kernel
