194	public:
195	
196	  /// Determines whether the GEMM can execute the given problem.
197	  static Status
198	  can_implement(Arguments const& args) {
199	    Status status = Status::kSuccess;
200	
201	    status = OperationSumOdO::can_implement(to_sum_OdO_arguments(args));
202	    if (status != Status::kSuccess) {
203	      return status;
204	    }
205	
206	    status = OperationConvert::can_implement(to_convert_arguments(args));
207	    if (status != Status::kSuccess) {
208	      return status;
209	    }
210	
