219	  /// Gets the workspace size
220	  static size_t
221	  get_workspace_size(Arguments const& args) {
222	    auto [Q_, K, D, D_VO, HB] = args.problem_shape;
223	    auto [H, B] = HB;
224	    D = cutlass::round_up(D, 8);  // Alignment
225	    int Q = cutlass::round_up(static_cast<int>(Q_), 8);  // Alignment
226	    size_t workspace_bytes = 0;
227	    // OdO vector
228	    workspace_bytes += sizeof(ElementAccumulator) * B*H*Q;
229	    // scaled LSE vector
230	    workspace_bytes += sizeof(ElementAccumulator) * B*H*Q;
231	    // FP32 versions of outputs that are churned (start off with Q only)
232	    workspace_bytes += sizeof(ElementAccumulator) * B*H*Q*D;
233	    return workspace_bytes;
234	  }
