236	  /// Initializes state from arguments.
237	  Status
238	  initialize_split(Arguments const& args, void* workspace_dQ, void* workspace_sum_OdO, void* workspace_scaled_lse, cudaStream_t stream = nullptr) {
239	    CUTLASS_TRACE_HOST("Universal::initialize_split() - workspace_dQ="
240	      << workspace_dQ << ", workspace_sum_OdO=" << workspace_sum_OdO << "stream: " << (stream ? "non-null" : "null"));
241	
242	    auto [Q_, K, D, D_VO, HB] = args.problem_shape;
243	    auto [H, B] = HB;
244	    D = cutlass::round_up(D, 8);  // Alignment
245	    int Q = cutlass::round_up(static_cast<int>(Q_), 8);  // Alignment
246	    ElementAccumulator* sum_OdO = reinterpret_cast<ElementAccumulator*>(workspace_sum_OdO);
247	    ElementAccumulator* scaled_lse = reinterpret_cast<ElementAccumulator*>(workspace_scaled_lse);
248	    ElementAccumulator* dQ_acc = reinterpret_cast<ElementAccumulator*>(workspace_dQ);
249	    params_.dQ_acc = dQ_acc;
250	    params_.dQ_acc_size = sizeof(ElementAccumulator) * B*H*Q*D;
251	    auto args_sum_OdO = to_sum_OdO_arguments(args, sum_OdO, scaled_lse);
252	    auto args_convert = to_convert_arguments(args, dQ_acc);
253	    params_.op_sum_OdO.initialize(args_sum_OdO, nullptr, stream);
254	    params_.op_convert.initialize(args_convert, nullptr, stream);
255	    auto args_bwd = to_bwd_arguments(
256	        args, sum_OdO, args_sum_OdO.stride_sum_OdO,
257	        scaled_lse, args_sum_OdO.stride_scaled_lse,
258	        dQ_acc, args_convert.stride_src_dQ
259	    );
260	    params_.op.initialize(args_bwd, nullptr, stream);
261	
262	    return Status::kSuccess;
263	  }
264	
265	  /// Initializes state from arguments.
266	  Status
267	  initialize(Arguments const& args, void* workspace = nullptr, cudaStream_t stream = nullptr) {
268	    CUTLASS_TRACE_HOST("Universal::initialize() - workspace "
269	      << workspace << ", stream: " << (stream ? "non-null" : "null"));
270	
271	    auto [Q_, K, D, D_VO, HB] = args.problem_shape;
272	    auto [H, B] = HB;
273	    D = cutlass::round_up(D, 8);  // Alignment
274	    int Q = cutlass::round_up(static_cast<int>(Q_), 8);  // Alignment
275	    char* workspace_chr = reinterpret_cast<char*>(workspace);
276	    ElementAccumulator* sum_OdO = reinterpret_cast<ElementAccumulator*>(workspace_chr);
277	    workspace_chr += sizeof(ElementAccumulator) * B*H*Q;
278	    ElementAccumulator* scaled_lse = reinterpret_cast<ElementAccumulator*>(workspace_chr);
279	    workspace_chr += sizeof(ElementAccumulator) * B*H*Q;
280	    ElementAccumulator* dQ_acc = reinterpret_cast<ElementAccumulator*>(workspace_chr);
281	    return initialize_split(args, dQ_acc, sum_OdO, scaled_lse, stream);
282	  }
283	
284	  /// Primary run() entry point API that is static allowing users to create and manage their own params.
285	  /// Supplied params struct must be construct by calling Kernel::to_underling_arguments()
286	  static Status
287	  run(Params& params, cudaStream_t stream = nullptr) {
288	    CUTLASS_TRACE_HOST("FmhaDeviceBwd::run()");
289	
290	    Status result = Status::kSuccess;
291	    result = params.op_sum_OdO.run(stream);
292	    if (result != Status::kSuccess) {
293	      return result;
294	    }
295	
296	    auto cuda_result = cudaMemsetAsync(params.dQ_acc, 0, params.dQ_acc_size, stream);
297	    if (cuda_result != cudaSuccess) {
298	       return Status::kErrorInternal;
299	    }
300	
301	    result = params.op.run(stream);
302	    if (result != Status::kSuccess) {
303	      return result;
304	    }
305	
306	    result = params.op_convert.run(stream);
307	    if (result != Status::kSuccess) {
308	      return result;
309	    }
310	
311	    return Status::kSuccess;
312	  }
313	
314	  //
315	  // Non-static launch overloads that first create and set the internal params struct of this kernel handle.
316	  //
317	
318	  /// Launches the kernel after first constructing Params internal state from supplied arguments.
319	  Status
320	  run(Arguments const& args, void* workspace = nullptr, cudaStream_t stream = nullptr) {
321	    Status status = initialize(args, workspace, stream);
322	    if (Status::kSuccess == status) {
323	      status = run(params_, stream);
324	    }
325	    return status;
326	  }
327	
328	  /// Overload that allows a user to re-launch the same kernel without updating internal params struct.
329	  Status
330	  run(cudaStream_t stream = nullptr) {
331	    return run(params_, stream);
332	  }
